-- Script to update existing subjects with branch_id values\n-- Run this AFTER adding the new columns\n\n-- First, let's see what school_locations (branches) exist\nSELECT \n    school_id,\n    branch_id,\n    location_name,\n    status\nFROM school_locations \nWHERE status = 'Active'\nORDER BY school_id, branch_id;\n\n-- Check subjects that need branch_id updates\nSELECT \n    school_id,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT section) as sections\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = ''\nGROUP BY school_id;\n\n-- Option 1: Update all subjects to use the first active branch for each school\n-- UNCOMMENT AND MODIFY AS NEEDED:\n/*\nUPDATE subjects s\nJOIN (\n    SELECT \n        school_id,\n        MIN(branch_id) as default_branch_id\n    FROM school_locations \n    WHERE status = 'Active'\n    GROUP BY school_id\n) sl ON s.school_id = sl.school_id\nSET s.branch_id = sl.default_branch_id\nWHERE s.branch_id IS NULL OR s.branch_id = '';\n*/\n\n-- Option 2: Update subjects for a specific school with a specific branch\n-- UNCOMMENT AND MODIFY AS NEEDED:\n/*\nUPDATE subjects \nSET branch_id = 'BRCH00001'  -- Replace with your actual branch ID\nWHERE school_id = 'SCH/1'    -- Replace with your actual school ID\nAND (branch_id IS NULL OR branch_id = '');\n*/\n\n-- Option 3: Interactive update - shows what would be updated\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.section,\n    s.class_code,\n    'NEEDS_BRANCH_ID' as current_branch_id,\n    sl.branch_id as suggested_branch_id,\n    sl.location_name as branch_name\nFROM subjects s\nLEFT JOIN (\n    SELECT \n        school_id,\n        branch_id,\n        location_name,\n        ROW_NUMBER() OVER (PARTITION BY school_id ORDER BY branch_id) as rn\n    FROM school_locations \n    WHERE status = 'Active'\n) sl ON s.school_id = sl.school_id AND sl.rn = 1\nWHERE s.branch_id IS NULL OR s.branch_id = ''\nORDER BY s.school_id, s.section, s.subject;\n\n-- Verification query - run after updates\nSELECT \n    school_id,\n    branch_id,\n    section,\n    COUNT(*) as subject_count\nFROM subjects \nGROUP BY school_id, branch_id, section\nORDER BY school_id, branch_id, section;\n\n-- Final check - should return 0 rows if all subjects have branch_id\nSELECT COUNT(*) as subjects_without_branch_id\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n"